type Session = { accessToken: string; expiresAt: number } | null;

const Auth = createContext<{ session: Session; signOut: () => void } | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [session, setSession] = useState<Session>(null);
  useEffect(() => {
    if (!session) return;
    const t = setTimeout(() => {
      /* refresh: POST /auth/refresh, then setSession */
    }, session.expiresAt - Date.now() - 30_000);
    return () => clearTimeout(t);
  }, [session]);
  const v = useMemo(
    () => ({ session, signOut: () => setSession(null) }),
    [session]
  );
  return <Auth.Provider value={v}>{children}</Auth.Provider>;
}

